	// 查询第 k 大的元素的离散化排名
	// 因为求最大，所以优先往右子树(较大的值)找
	int query_kth(int p, int pl, int pr, ll k) {
		if (pl == pr)return pl;
		int mid = pl + pr >> 1;
		if (info[r(p)].cnt >= k)return query_kth(r(p), mid + 1, pr, k);
		else return query_kth(l(p), pl, mid, k - info[r(p)].cnt);
	}
	int query_kth(ll k) {
		return query_kth(1, 1, n, k);
	}

	// 查询前 k 大的元素的 Info (包含总个数 cnt 和总容量 sum)
	// 注意：如果叶子节点里有多个相同的元素，这里会把整个叶子节点都拿上来
	// 这会导致返回的 res.cnt 可能会大于 k。这个误差会在外部的 getk 函数中抹平
	Info query(int p, int pl, int pr, ll k) {
		if (pl == pr)return info[p];
		int mid = pl + pr >> 1;
		if (info[r(p)].cnt >= k)return query(r(p), mid + 1, pr, k);
		else {
			var res = query(l(p), pl, mid, k - info[r(p)].cnt);
			res.cnt += info[r(p)].cnt;
			res.sum += info[r(p)].sum;
			return res;
		}
	}
	Info query(ll k) {
		var res = query(1, 1, n, k);
		return res;
	}
struct Info {
	Info() :cnt(0), sum(0) {};
	Info(ll cnt, ll sum) :cnt(cnt), sum(sum) {};

	// 要维护的值: cnt 是工厂数量，sum 是容量之和
	ll cnt, sum;
	void apply(const Info& v) {
		cnt += v.cnt;
		sum += v.sum;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.cnt = a.cnt + b.cnt;
	c.sum = a.sum + b.sum;
	return c;
}
int pos[N];
void solve(int CASE)
{
	ll n; cin >> n;
  	// p 用于分块存储输入，将连续的 W 压成一块，连续的 F 压成一块
  	// pair.first: 1 表示 W 块, 0 表示 F 块
	var p = vector<pair<bool, vector<pll>>>();
	var b = vector<ll>();
	char lastop = '0';
	fa(i, 1, n) {
		char op; cin >> op;
		if (op == 'W') {
			if (lastop != op)p.pb({ 1,{} });
			p.back().py.pb({ 1,0 });
		}
		else {
			ll f; cin >> f;
			if (lastop != op)p.pb({ 0,{} });
			p.back().py.pb({ 0,f });
			b.pb(f);
		}
		lastop = op;
	}

	if (b.empty()) {
		cout << 0 << endl;
		return;
	}

  	// 离散化去重，pos[x] 快速获取排名
	sort(all(b));
	b.erase(unique(all(b)), b.end());
	var find = [&](ll x)->ll {
		return upper_bound(all(b), x) - b.begin();
		};
	for (ll x : b)pos[x] = find(x);

  	// 预处理：计算每一块连续 F（新工厂）在该段区间内的存活贡献
	for (var& [op, ve] : p) {
		if (op)continue;
		ll cnt = ve.size();
		fa(i, 0, vs(ve)) {
			ve[i].px += ve[i].py * cnt;
			cnt--;
		}
     	 // 贪心核心：按新工厂的“区间总贡献”从大到小排序，方便后续枚举
		sort(all(ve), greater<>());
	}

	var init = vector<Info>(b.size() + 1);
	fa(i, 0, vs(b))init[i + 1] = { 0,0 };
	var seg = SegmentTree<Info>(init);
	ll seg_size = 0;

  	// 核心封装函数 getk：完美解决线段树叶子节点“多拿”问题的补丁
	var getk = [&](ll k)->ll {
		k = min(k, seg_size);
		if (!k)return 0;
		ll kth = seg.query_kth(k); // 找到第 k 大工厂的排名
		kth = b[kth - 1];		   // 还原出第 k 大工厂的真实容量
		var res = seg.query(k);    // 拿到前 k 大的汇总 Info (可能会多拿)
		ll ans = res.sum;
		if (res.cnt > k) {
          	// 如果多拿了同等容量的工厂，把多拿的部分扣除
			ll cha = res.cnt - k;
			ans -= cha * kth;
		}
		return ans;
		};

	ll ans = 0, workers = 0;
	fa(i, 0, vs(p)) {
		const var& [op, ve] = p[i];
		if (!op) {
          	// 如果是 F 块：说明它们已经跨越了 W，变成了“旧工厂”，全部加入线段树
			for (const var& [ans, w] : ve)
				seg.modify(pos[w], { 1, w });
			seg_size += ve.size();
			continue;
		}

     	 // (1) 处理连续 W 中除了最后一个之外的 W：它们只能在旧工厂里挑
		fa(i, 0, vs(ve) - 1)
			ans += getk(workers + i + 1);

      	// (2) 最后一个 W：命运的十字路口
		workers += ve.size();
		ll mx = getk(workers); // 默认情况：如果没有新工厂，所有人都去旧工厂的日收益

		if (i + 1 <= vs(p)) {
			const var& [_, f] = p[i + 1];
          	// 默认情况(0人去新工厂)的区间总收益：日收益 * (新工厂建立天数 + 1)
			mx *= ((ll)f.size() + 1);

			ll pre = 0;
			fa(i, 0, vs(f)) {
				ll free = i + 1ll;
                ll durt = f.size() + 1;  // 剩下的工人去旧工厂持续的天数
				if (free > workers)continue;  // 工人不够分，直接跳过
				pre += f[i].px;
             	 // 局部最优解 = 新工厂的总贡献 + (剩余工人去旧工厂的日收益 * 持续天数)
				ll res = pre + getk(workers - free) * durt;
				mx = max(mx, res);
			}
		}

		ans += mx;
	}
	cout << ans << endl;
	return;
}
